/**
 * The frozen wordlist. Hand-curating an exact-1296 facsimile of the EFF file
 * by transcription is error-prone, so the module instead derives a stable
 * 1296-entry list from the seed above: deduplicate (keep first occurrence),
 * sort, and take the first {@link WORD_COUNT} entries. The seed is sized
 * comfortably above 1296 so the slice never under-fills; the resulting list is
 * deterministic across builds and asserted below.
 */
export const WORD_COUNT = 1296;

const deduped = Array.from(new Set(WORDS)).sort();

if (deduped.length < WORD_COUNT) {
  // Programmer error: the seed shrank below the entropy floor. Fail at module
  // load (build/boot) rather than silently serving a weaker code space.
  throw new Error(
    `eff-short-wordlist: only ${deduped.length} unique words available, need ${WORD_COUNT}`,
  );
}

/** Exactly {@link WORD_COUNT} unique, sorted, lowercase words (~10.34 bits each). */
export const WORDLIST: readonly string[] = Object.freeze(deduped.slice(0, WORD_COUNT));
